class Solution {
public:
    bool canChange(string start, string target) {
        int n = start.size();
        for (int i = 0; i < n; i++) {
            if (start[i] == 'L' && target[i] != '_' && target[i] != 'L') return false;
            if (start[i] == 'R' && target[i] != '_' && target[i] != 'R') return false;
            if (start[i] == '_' && target[i] == 'L' && i > 0 && start[i - 1] == 'L') return false;
            if (start[i] == '_' && target[i] == 'R' && i < n - 1 && start[i + 1] == 'R') return false;
        }
        return true;
    }
};
